c
/* Technical Reference: Free List Init /
typedef struct Block {
struct Block next;     // Offset 0 (8 bytes)
uint8_t data[56];       // Offset 8 (56 bytes)
} Block;

void pool_init(void* mem, size_t n) {
Block* pool = (Block*)mem;
for (size_t i = 0; i < n - 1; ++i) {
pool[i].next = &pool[i + 1]; // Set link to contiguous next
}
pool[n - 1].next = NULL;         // Terminal sentinel
}

